import{b as n,I as t,g as a,j as s}from"./chunks/framework.DUo3J_Qe.js";const m=JSON.parse('{"title":"U-Net","description":"","frontmatter":{},"headers":[],"relativePath":"fr/learning/deep-learning/unet.md","filePath":"fr/learning/deep-learning/unet.md"}'),r={name:"fr/learning/deep-learning/unet.md"};function o(i,e,l,p,d,u){return t(),a("div",null,[...e[0]||(e[0]=[s(`<h1 id="u-net" tabindex="-1">U-Net <a class="header-anchor" href="#u-net" aria-label="Permalink to &quot;U-Net&quot;">​</a></h1><h2 id="le-probleme-de-la-segmentation-avec-un-cnn-classique" tabindex="-1">Le problème de la segmentation avec un CNN classique <a class="header-anchor" href="#le-probleme-de-la-segmentation-avec-un-cnn-classique" aria-label="Permalink to &quot;Le problème de la segmentation avec un CNN classique&quot;">​</a></h2><p>Un CNN classique réduit progressivement la taille de l&#39;image (via pooling) pour extraire des informations de haut niveau. À la fin, on obtient une représentation compacte — utile pour classifier (&quot;c&#39;est un arbre&quot;) mais inutilisable pour segmenter (on a perdu la position spatiale).</p><p>Pour la segmentation, il faut <strong>reconstruire</strong> une image de la même taille que l&#39;entrée. C&#39;est le problème qu&#39;U-Net résout.</p><h2 id="l-architecture-en-u" tabindex="-1">L&#39;architecture en U <a class="header-anchor" href="#l-architecture-en-u" aria-label="Permalink to &quot;L&#39;architecture en U&quot;">​</a></h2><p>U-Net doit son nom à sa forme visuelle : une descente (encodeur) suivie d&#39;une remontée symétrique (décodeur).</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Image                                              Masque</span></span>
<span class="line"><span>256×256×3                                        256×256×1</span></span>
<span class="line"><span>    │                                                 ▲</span></span>
<span class="line"><span>    ▼                                                 │</span></span>
<span class="line"><span>┌────────┐                                       ┌────────┐</span></span>
<span class="line"><span>│  Conv  │ ──────── skip connection ──────────▶ │  Conv  │</span></span>
<span class="line"><span>│128×128 │                                       │128×128 │</span></span>
<span class="line"><span>└────┬───┘                                       └───▲────┘</span></span>
<span class="line"><span>     ▼                                               │</span></span>
<span class="line"><span>┌────────┐                                       ┌────────┐</span></span>
<span class="line"><span>│  Conv  │ ──────── skip connection ──────────▶ │  Conv  │</span></span>
<span class="line"><span>│  64×64 │                                       │  64×64 │</span></span>
<span class="line"><span>└────┬───┘                                       └───▲────┘</span></span>
<span class="line"><span>     ▼                                               │</span></span>
<span class="line"><span>┌────────┐                                       ┌────────┐</span></span>
<span class="line"><span>│  Conv  │ ──────── skip connection ──────────▶ │  Conv  │</span></span>
<span class="line"><span>│  32×32 │                                       │  32×32 │</span></span>
<span class="line"><span>└────┬───┘                                       └───▲────┘</span></span>
<span class="line"><span>     ▼                                               │</span></span>
<span class="line"><span>         ┌──────────────────────┐</span></span>
<span class="line"><span>         │   Bottleneck 16×16   │</span></span>
<span class="line"><span>         └──────────────────────┘</span></span></code></pre></div><h3 id="l-encodeur-descente" tabindex="-1">L&#39;encodeur (descente) <a class="header-anchor" href="#l-encodeur-descente" aria-label="Permalink to &quot;L&#39;encodeur (descente)&quot;">​</a></h3><p>Identique à un CNN classique : des couches de convolution + pooling qui réduisent la résolution et augmentent le nombre de filtres. À chaque étape, le réseau voit des structures de plus en plus abstraites (bords → textures → formes → objets).</p><h3 id="le-decodeur-remontee" tabindex="-1">Le décodeur (remontée) <a class="header-anchor" href="#le-decodeur-remontee" aria-label="Permalink to &quot;Le décodeur (remontée)&quot;">​</a></h3><p>L&#39;opération inverse : des <strong>convolutions transposées</strong> (ou upsampling) qui remontent progressivement vers la résolution d&#39;origine. À chaque étape, la résolution double et le nombre de filtres est divisé par deux.</p><h3 id="les-skip-connections-—-la-cle-du-u-net" tabindex="-1">Les skip connections — la clé du U-Net <a class="header-anchor" href="#les-skip-connections-—-la-cle-du-u-net" aria-label="Permalink to &quot;Les skip connections — la clé du U-Net&quot;">​</a></h3><p>À chaque niveau, la feature map de l&#39;encodeur est <strong>concaténée</strong> avec celle du décodeur correspondant. C&#39;est ce qui différencie U-Net de toutes les architectures précédentes.</p><p><strong>Pourquoi c&#39;est crucial :</strong> l&#39;encodeur compresse l&#39;information (et perd la localisation précise). Les skip connections court-circuitent cette perte : le décodeur reçoit à la fois le contexte global (du bottleneck) et les détails fins (de l&#39;encodeur).</p><p>Analogie : imagine que tu dois redessiner une carte de mémoire après l&#39;avoir vue réduite à un timbre-poste. Les skip connections te permettent de consulter la carte originale à chaque zoom — tu gardes les détails tout en comprenant la structure globale.</p><h2 id="pourquoi-u-net-pour-geoml" tabindex="-1">Pourquoi U-Net pour GeoML ? <a class="header-anchor" href="#pourquoi-u-net-pour-geoml" aria-label="Permalink to &quot;Pourquoi U-Net pour GeoML ?&quot;">​</a></h2><p>Quatre raisons ont motivé ce choix :</p><table tabindex="0"><thead><tr><th>Critère</th><th>U-Net</th><th>Alternatives</th></tr></thead><tbody><tr><td><strong>Petits datasets</strong></td><td>Fonctionne avec peu d&#39;exemples</td><td>ResNet, VGG → nécessitent des millions d&#39;images</td></tr><tr><td><strong>Contours précis</strong></td><td>Skip connections préservent les détails fins</td><td>YOLO → boîtes rectangulaires seulement</td></tr><tr><td><strong>Images haute résolution</strong></td><td>Conçu pour des patches (256×256)</td><td>Transformers vision → très gourmands en mémoire</td></tr><tr><td><strong>Origine</strong></td><td>Conçu pour la segmentation d&#39;images médicales (petits objets, formes précises) — très similaire aux couronnes d&#39;arbres vues du ciel</td><td>—</td></tr></tbody></table><h2 id="les-alternatives-ecartees" tabindex="-1">Les alternatives écartées <a class="header-anchor" href="#les-alternatives-ecartees" aria-label="Permalink to &quot;Les alternatives écartées&quot;">​</a></h2><p><strong>Classification (ResNet, VGG…)</strong> — répond à &quot;y a-t-il un arbre ?&quot;, pas à &quot;où exactement&quot;. Inutilisable pour extraire des polygones.</p><p><strong>Détection (YOLO, Faster R-CNN)</strong> — prédit des boîtes englobantes rectangulaires. Pour des arbres ronds vus du dessus, la boîte encadre autant de toit ou de route que d&#39;arbre.</p><p><strong>DeepLab / SegFormer</strong> — architectures plus récentes, plus précises sur de grands datasets. Trop lourdes à entraîner depuis zéro sur notre volume de données.</p><p><strong>EGI seul (méthode classique)</strong> — pas de machine learning. Rapide, mais confond gazon/champs/forêts et échoue sur les zones ombragées ou les espèces à feuillage sombre.</p><h2 id="ce-que-u-net-apprend-que-egi-ne-voit-pas" tabindex="-1">Ce que U-Net apprend que EGI ne voit pas <a class="header-anchor" href="#ce-que-u-net-apprend-que-egi-ne-voit-pas" aria-label="Permalink to &quot;Ce que U-Net apprend que EGI ne voit pas&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Situation</th><th>EGI</th><th>U-Net</th></tr></thead><tbody><tr><td>Arbre en zone ombragée</td><td>❌ Rate (pas assez vert)</td><td>✅ Reconnaît la texture de couronne</td></tr><tr><td>Gazon / pelouse</td><td>❌ Confond avec arbre</td><td>✅ Distingue par la texture et la forme</td></tr><tr><td>Toit végétalisé</td><td>❌ Confond</td><td>✅ Apprend la différence de contexte</td></tr><tr><td>Arbre à feuillage sombre</td><td>❌ Rate</td><td>✅ Reconnaît la forme arrondie</td></tr></tbody></table>`,25)])])}const h=n(r,[["render",o]]);export{m as __pageData,h as default};
